import{_ as t,o as a,c as s,a3 as o}from"./chunks/framework.LBeL10WQ.js";const y=JSON.parse('{"title":"Billing & Payments","description":"","frontmatter":{"title":"Billing & Payments"},"headers":[],"relativePath":"en/faq/billing.md","filePath":"en/faq/billing.md"}'),n={name:"en/faq/billing.md"};function i(r,e,l,d,c,u){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="billing-payments" tabindex="-1">Billing &amp; Payments <a class="header-anchor" href="#billing-payments" aria-label="Permalink to &quot;Billing &amp; Payments&quot;">​</a></h1><details class="details custom-block"><summary>I don&#39;t see my revenue in my Wallet</summary><p>The credit is not automatic upon signature, but upon <strong>realization</strong>. You must manually validate according to the format:</p><ul><li><strong>Parcel Insert:</strong> Have you filled out your weekly volume declaration? (On Monday or Tuesday)</li><li><strong>Email:</strong> Did you click on <strong>&quot;Validate broadcast&quot;</strong> after sending?</li></ul><p>Without this action, the funds remain escrowed.</p></details><details class="details custom-block"><summary>How to withdraw my earnings and issue my invoice?</summary><p>Go to <strong>Transaction → Exchange</strong> and click on <code>Withdraw</code>. Enter the amount.</p><p><strong>Important:</strong> If management fees apply, issue your invoice accordingly for the net amount received.</p></details><details class="details custom-block"><summary>When are the revenues available?</summary><p>The campaign revenue is credited to your account balance <strong>30 days after the last reporting</strong>. Then choose <code>Transfer to wallet</code> or <code>Withdraw</code> your revenue.</p></details><details class="details custom-block"><summary>When are payments issued?</summary><p>Payments are issued <strong>30 days end of month</strong>, from the date of receipt of the withdrawal request, provided that the submitted invoice is valid.</p></details><details class="details custom-block"><summary>Can I reinvest my earnings?</summary><p>Yes, without fees. In <strong>Exchange</strong>, click on <code>Transfer to wallet</code>. You can use this balance immediately to buy traffic for your own site.</p></details><details class="details custom-block"><summary>Why is my revenue blocked for 30 days?</summary><p>The 30-day delay is a <strong>protection period</strong> that secures your payment and that of the advertiser.</p><p>It allows detecting and processing potential anomalies (lost boxes, non-compliant volumes, interrupted campaign) <strong>before</strong> the funds are definitively released. Without this buffer, getinside could not guarantee your payment in the event of advertiser default.</p></details><details class="details custom-block"><summary>What happens if an anomaly is detected during the 30 days?</summary><p>getinside contacts you directly to resolve the incident. During the resolution, the delay for the availability of funds is suspended. Once the anomaly is handled, the counter resumes.</p><p>In common cases (volume discrepancy, non-compliant flyer), the resolution takes 48 to 72 hours. Contact <a href="mailto:support@getinside.fr" target="_blank" rel="noreferrer">support@getinside.fr</a> if you don&#39;t receive feedback within 5 working days.</p></details><details class="details custom-block"><summary>Can my funds expire?</summary><p>Yes. If you do not log in <strong>and</strong> do not withdraw your revenue for <strong>12 consecutive months</strong>, the available funds expire and are definitively acquired by getinside.</p><p><strong>How to avoid this:</strong> log in regularly, or enable balance notifications in your account space. A partial withdrawal or reinvestment is enough to reset the counter.</p></details>',9)])])}const p=t(n,[["render",i]]);export{y as __pageData,p as default};
